const variables = automaRefData('variables', '');
const newCode = variables.add_property_code;
const newName = variables.add_property_name;

const addBtn = Array.from(document.querySelectorAll('button')).find(b => b.innerText.includes('Add Value'));
if (addBtn) addBtn.click();

setTimeout(() => {
  const handles = document.querySelectorAll('.drag-handle');
  const lastRow = handles[handles.length - 1]?.closest('.group');
  if (lastRow) {
    const inputs = lastRow.querySelectorAll('input');
    if (inputs[0]) {
      inputs[0].value = newCode;
      inputs[0].dispatchEvent(new Event('input', { bubbles: true }));
    }
    if (inputs[1]) {
      inputs[1].value = newName;
      inputs[1].dispatchEvent(new Event('input', { bubbles: true }));
    }
  }

  const saveBtn = Array.from(document.querySelectorAll('button')).find(b => b.innerText.includes('Save') && !b.disabled);
  if (saveBtn) saveBtn.click();
  setTimeout(() => automaNextBlock(), 1000);
}, 500);
